 1	import * as React from 'react';
 2	import { useGetInternalClusterDetails } from '@odf/core/redux/utils';
 3	import { EfficiencyItemBody } from '@odf/shared/dashboards/storage-efficiency/storage-efficiency-card-item';
 4	import {
 5	  useCustomPrometheusPoll,
 6	  usePrometheusBasePath,
 7	} from '@odf/shared/hooks/custom-prometheus-poll';
 8	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 9	import { getGaugeValue, humanizeBinaryBytes } from '@odf/shared/utils';
10	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
11	import {
12	  POOL_STORAGE_EFFICIENCY_QUERIES,
13	  StorageDashboardQuery,
14	} from '../../../queries';
15	
16	export const StorageEfficiencyContent: React.FC = () => {
17	  const { t } = useCustomTranslation();
18	
19	  const { clusterName: managedByOCS } = useGetInternalClusterDetails();
20	
21	  const [poolCapacityRatioResult, poolCapacityRatioResultError] =
22	    useCustomPrometheusPoll({
23	      query:
24	        POOL_STORAGE_EFFICIENCY_QUERIES(managedByOCS)[
25	          StorageDashboardQuery.POOL_CAPACITY_RATIO
26	        ],
27	      endpoint: 'api/v1/query' as any,
28	      basePath: usePrometheusBasePath(),
29	    });
30	
31	  const [poolSavedResult, poolSavedResultError] = useCustomPrometheusPoll({
32	    query:
33	      POOL_STORAGE_EFFICIENCY_QUERIES(managedByOCS)[
34	        StorageDashboardQuery.POOL_SAVED_CAPACITY
35	      ],
36	    endpoint: 'api/v1/query' as any,
37	    basePath: usePrometheusBasePath(),
38	  });
39	  const ratio = getGaugeValue(poolCapacityRatioResult);
40	  const saved = getGaugeValue(poolSavedResult);
41	
42	  const compressionStats = () => {
43	    const capacityRatio = Number(ratio);
44	    return t('{{capacityRatio, number}}:1', {
45	      capacityRatio: Math.round(capacityRatio),
46	    });
47	  };
48	
49	  const savingStats = () => {
50	    const savingsValue = Number(saved);
51	    const savedBytes = humanizeBinaryBytes(savingsValue).string;
52	    return savedBytes;
53	  };
54	
55	  const compressionRatioProps = {
56	    stats: Number(ratio),
57	    isLoading: !poolCapacityRatioResult && !poolCapacityRatioResultError,
58	    error: !!poolCapacityRatioResultError || !ratio,
59	    title: t('Compression ratio'),
60	    infoText: t(
61	      'The Compression Ratio represents the compressible data effectiveness metric inclusive of all compression-enabled pools.'
62	    ),
63	    getStats: compressionStats,
64	  };
65	
66	  const savingsProps = {
67	    stats: Number(saved),
68	    isLoading: !poolSavedResult && !poolSavedResultError,
69	    error: !!poolSavedResultError || !saved,
70	    title: t('Savings'),
71	    infoText: t(
72	      'The Savings metric represents the actual disk capacity saved inclusive of all compression-enabled pools and associated replicas.'
73	    ),
74	    getStats: savingStats,
75	  };
76	  return (
77	    <>
78	      <EfficiencyItemBody {...compressionRatioProps} />
79	      <EfficiencyItemBody {...savingsProps} />
80	    </>
81	  );
82	};
83	
84	const StorageEfficiencyCard: React.FC = () => {
85	  const { t } = useCustomTranslation();
86	  return (
87	    <Card>
88	      <CardHeader>
89	        <CardTitle>{t('Storage efficiency')}</CardTitle>
90	      </CardHeader>
91	      <CardBody>
92	        <StorageEfficiencyContent />
93	      </CardBody>
94	    </Card>
95	  );
96	};
97	
98	export default StorageEfficiencyCard;

